import{_ as i,o as s,c as e,ag as l}from"./chunks/framework.gU7RhlGX.js";const k=JSON.parse('{"title":"OpenClaw 语音交互（Noiz AI 驱动）","description":"","frontmatter":{},"headers":[],"relativePath":"openclaw/openclaw 可以说话.md","filePath":"openclaw/openclaw 可以说话.md","lastUpdated":1776422487000}'),n={name:"openclaw/openclaw 可以说话.md"};function t(r,a,o,p,h,d){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="openclaw-语音交互-noiz-ai-驱动" tabindex="-1">OpenClaw 语音交互（Noiz AI 驱动） <a class="header-anchor" href="#openclaw-语音交互-noiz-ai-驱动" aria-label="Permalink to &quot;OpenClaw 语音交互（Noiz AI 驱动）&quot;">​</a></h1><p>让你的 OpenClaw 助手拥有“有温度”的声音。通过集成 Noiz AI 引擎，OpenClaw 不再仅仅是文字回复，而是可以像真人一样与你对话，甚至能捕捉和表达细腻的情绪。</p><h2 id="🌟-核心优势-为什么选择-noiz-ai" tabindex="-1">🌟 核心优势：为什么选择 Noiz AI？ <a class="header-anchor" href="#🌟-核心优势-为什么选择-noiz-ai" aria-label="Permalink to &quot;🌟 核心优势：为什么选择 Noiz AI？&quot;">​</a></h2><p>Noiz 是一款专注于<strong>高拟真、具情感</strong>声音生成的 AI 平台，其技术优势包括：</p><ul><li><strong>极致真人感</strong>：超越传统的“机器音”，Noiz 能生成自然停顿、叹气和语调起伏，让 AI 声音像真人一样“会呼吸”。</li><li><strong>情绪表达控制</strong>：支持细致的情绪调节（如欢快、深情、愤怒等），适用于 Vlog 旁白、有声书、NPC 对话等多种场景。</li><li><strong>极速声音克隆</strong>：支持“一次录制，永久使用”。仅需简短音频样本即可克隆出高保真音色，实现“用你的声音说外语”。</li><li><strong>原生消息集成</strong>：生成的语音可以直接作为原生语音消息发送至<strong>飞书 (Feishu)</strong>、Telegram 或 Discord。</li><li><strong>隐私与本地化</strong>：支持在本地运行技能，确保敏感文本和资产的安全性。</li></ul><h2 id="🚀-安装与配置" tabindex="-1">🚀 安装与配置 <a class="header-anchor" href="#🚀-安装与配置" aria-label="Permalink to &quot;🚀 安装与配置&quot;">​</a></h2><p>你可以通过指令快速为 OpenClaw 安装语音技能：</p><h3 id="_1-安装技能" tabindex="-1">1. 安装技能 <a class="header-anchor" href="#_1-安装技能" aria-label="Permalink to &quot;1. 安装技能&quot;">​</a></h3><p>向你的 OpenClaw 助手发送：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我安装一下 https://github.com/NoizAI/skills</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者在终端手动执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装基础 TTS 技能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NoizAI/skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --full-depth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-配置-api-key-推荐" tabindex="-1">2. 配置 API Key（推荐） <a class="header-anchor" href="#_2-配置-api-key-推荐" aria-label="Permalink to &quot;2. 配置 API Key（推荐）&quot;">​</a></h3><p>为了获得最佳的情绪控制和高保真效果，建议配置 Noiz API Key：</p><ol><li>从 <a href="https://developers.noiz.ai/api-keys" target="_blank" rel="noreferrer">developers.noiz.ai</a> 获取 API Key。</li><li>在终端执行：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills/tts/scripts/tts.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-api-key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 你的_API_KEY</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><em>注：你也可以通过 <code>--backend kokoro</code> 使用本地 Kokoro 后端（无需 API Key，但功能受限）。</em></li></ol><h2 id="🛠️-进阶语音技能" tabindex="-1">🛠️ 进阶语音技能 <a class="header-anchor" href="#🛠️-进阶语音技能" aria-label="Permalink to &quot;🛠️ 进阶语音技能&quot;">​</a></h2><p>安装完成后，你可以探索以下进阶技能：</p><ul><li><strong>tts</strong>：基础文本转语音并交付。</li><li><strong>characteristic-voice</strong>：使用特定的性格预设（如冷静、兴奋等）进行表达。</li><li><strong>video-translation</strong>：视频一站式翻译与配音，支持口型同步 (Lip-Sync)。</li><li><strong>daily-news-caster</strong>：生成新闻播报风格的语音内容。</li></ul><h2 id="🔗-相关资源" tabindex="-1">🔗 相关资源 <a class="header-anchor" href="#🔗-相关资源" aria-label="Permalink to &quot;🔗 相关资源&quot;">​</a></h2><ul><li><strong>Noiz 官网</strong>: <a href="https://noiz.ai" target="_blank" rel="noreferrer">noiz.ai</a></li><li><strong>GitHub 技能库</strong>: <a href="https://github.com/NoizAI/skills" target="_blank" rel="noreferrer">NoizAI/skills</a></li><li><strong>参考资料</strong>: <ul><li><a href="https://aixzd.com/noiz" target="_blank" rel="noreferrer">AI 星踪岛 - Noiz 详细介绍与评价</a></li><li><a href="https://blog.csdn.net/Vincentqqqqqqq/article/details/144961316" target="_blank" rel="noreferrer">CSDN - Noiz AI TTS 和视频配音神器</a></li></ul></li></ul>`,20)])])}const g=i(n,[["render",t]]);export{k as __pageData,g as default};
